header = ["Date","Day","Post Number","Time","Content Type","Platform","Hook / Caption","Caption Variation 1","Caption Variation 2","Visual Direction","CTA","Goal","Color Code","Notes"]

rows = [header]
for day_num in range(1,31):
    d = start + timedelta(days=day_num-1)
    date_str = d.strftime("%d/%m/%Y")
    for post in days[day_num]:
        pnum, ctype, platform, hook, v1, v2, visual, cta, goal, notes = post
        color = colors.get(ctype, "#FFFFFF")
        rows.append([date_str, day_num, pnum, times[pnum], ctype, platform, hook, v1, v2, visual, cta, goal, color, notes])

with open("/home/mage107/Documents/projects/hotica/conversion/hotica_30day_calendar_v2.csv","w",newline="",encoding="utf-8") as f:
    csv.writer(f, quoting=csv.QUOTE_ALL).writerows(rows)

print(f"Done. {len(rows)-1} rows.")
